code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let arr;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        arr = line.split(' ').map(num => parseInt(num));
        let dp = new Array(n).fill(1);
        for (let j = 1; j < n; j++) {
            for (let k = 0; k < j; k++) {
                if (arr[j] >= arr[k]) {
                    dp[j] = Math.max(dp[j], dp[k] + 1);
                }
            }
        }
        let max = Math.max(...dp);
        console.log(n - max);
    }
    i++;
    if (i > 1) {
        readline.close();
    }
});
